// Initialize Autumn SDK with secret key from environment variable
const autumn = new Autumn(process.env.AUTUMN_SECRET_KEY);

// Get or create customer with specified parameters
const customer = await autumn.customers.getOrCreate({
  customerId: 'user_test_001',
  name: 'Alice Testuser',
  email: 'alice@example.com'
});

// Print the result as JSON to stdout
console.log(JSON.stringify(customer, null, 2));

